mapper.select:
SELECT IFNULL(sum(a.logistics_freight),0) AS logisticsFreight
    from jsh_warehouse_management a
    where a.type like '%发货%' and a.depot_id=#{number}

SELECT any_value(commodity_name) as commodityName, sum(numbers) as numbers, date_format(create_time,'%Y') as years, sum(total_financial_price) as amount, count(id) as depots from jsh_depot_head WHERE delete_flag=0
AND DATE_FORMAT(create_time,'%Y-%m-%d') between #{param.beginTime} and #{param.endTime}
AND creator in
#{item}
GROUP BY commodity_name,date_format(create_time,'%Y') ORDER BY date_format(create_time,'%Y') asc,sum(total_financial_price) DESC

SELECT any_value(commodity_name) as commodityName, date_format(create_time,'%Y') as years, any_value(commodity_no) as commodityNo, any_value(color) as color, sum(numbers) as numbers, sum(total_financial_price) as amount, count(id) as depots from jsh_depot_head WHERE delete_flag=0
AND DATE_FORMAT(create_time,'%Y-%m-%d') between #{param.beginTime} and #{param.endTime}
AND commodity_no=#{param.commodityNo}
AND date_format(create_time,'%Y')=#{param.years}
AND commodity_name like concat('%',#{param.commodityName},'%')
AND creator in
#{item}
GROUP BY commodity_no,date_format(create_time,'%Y') ORDER BY date_format(create_time,'%Y') asc ,count(id) DESC
limit #{param.limit}

SELECT any_value(sales_man) as salesMan, sum(numbers) as numbers, date_format(create_time,'%Y') as years, sum(total_financial_price) as amount, count(id) as depots from jsh_depot_head WHERE delete_flag=0
AND DATE_FORMAT(oper_time,'%Y-%m-%d') between #{param.beginTime} and #{param.endTime}
AND creator in
#{item}
GROUP BY sales_man,date_format(create_time,'%Y') ORDER BY date_format(create_time,'%Y') asc,sum(total_financial_price) DESC
